label("$A$",A,SE); label("$C$",C,E); draw(B--A--C); label("$r_B$",(A+B)/2,W); label("$r_A$",(A+C)/2,E); label("$r_B-r_A$",(B+C)/2,S);[/asy] <asy>import graph;
unitsize(3cm);
pair B = (0,0), A = (1,-3), C = (1,0); draw(B--A--C); label(scale(1.2)*"$r_B$", (A+B)/2,WSW,fontsize(10pt)); label(scale(1.2)*"$r_A$", (A+C)/2,SE,fontsize(10pt)); label(scale(1.2)*"$r_B-r_A$", (B+C)/2,S,fontsize(10pt));[/asy] \[ (r_B-r_A)^2+5^2=r_B^2. \]Since $r_B=8$, we can solve for $r_A$: \begin{align*}
(r_B-r_A)^2+5^2&=r_B^2\\
(8-r_A)^2+5^2&=8^2\\
(r_A-8)^2+25&=64\\
(r_A-8)^2&=39\\
r_A-8&=\pm\sqrt{39}\\
r_A&=8\pm\sqrt{39}
\end{align*}Therefore, the diameter of circle $A$ is $\boxed{16\pm2\sqrt{39}}$ cm.

